    if n == 1:
        return [((0, 0),)]

    shapes = set()

    def add_shape(shape):
        # Normalize the shape to avoid duplicates due to rotation and reflection
        min_x = min(x for x, y in shape)
        min_y = min(y for x, y in shape)
        normalized = tuple(sorted((x - min_x, y - min_y) for x, y in shape))
        shapes.add(normalized)

    def place_shape(shape, x, y):
        new_shape = tuple((x + dx, y + dy) for dx, dy in shape)
        add_shape(new_shape)

    def build_shape(current_shape, remaining):
        if remaining == 0:
            add_shape(current_shape)
            return

        for x, y in current_shape:
            for dx, dy in [(1, 0), (0, 1), (-1, 0), (0, -1)]:
                new_x, new_y = x + dx, y + dy
                if (new_x, new_y) not in current_shape:
                    build_shape(current_shape + ((new_x, new_y),), remaining - 1)

    initial_shape = ((0, 0),)
    build_shape(initial_shape, n - 1)

    return list(shapes)

