def generate_shapes(n):
    if n == 1:
        return [[[1]]]
    elif n == 2:
        return [[[1, 1]]]

    shapes = []

    def add_shape(shape):
        if shape not in shapes:
            shapes.append(shape)

    def rotate(shape):
        return [list(row) for row in zip(*shape[::-1])]

    def flip(shape):
        return [row[::-1] for row in shape]

    def normalize(shape):
        return sorted(map(tuple, shape))

    def generate(n, current_shape):
        if len(current_shape) == n:
            add_shape(current_shape)
            return

        for i in range(len(current_shape)):
            for j in range(len(current_shape[i])):
                if current_shape[i][j] == 0:
                    continue

                for dx, dy in [(0, 1), (1, 0), (0, -1), (-1, 0)]:
                    new_shape = [row[:] for row in current_shape]
                    new_x, new_y = i + dx, j + dy

                    if 0 <= new_x < len(new_shape) and 0 <= new_y < len(new_shape[0]) and new_shape[new_x][new_y] == 0:
                        new_shape[new_x][new_y] = 1
                        generate(n, normalize(new_shape))
                        new_shape[new_x][new_y] = 0

    initial_shape = [[1] + [0] * (n - 1)]
    generate(n, normalize(initial_shape))

    unique_shapes = []
    for shape in shapes:
        rotated_shapes = [shape]
        for _ in range(3):
            shape = rotate(shape)
            rotated_shapes.append(shape)

        flipped_shapes = [flip(s) for s in rotated_shapes]
        unique_shapes.extend(rotated_shapes + flipped_shapes)

    unique_shapes = {tuple(map(tuple, shape)) for shape in unique_shapes}

    return len(unique_shapes), unique_shapes

