def generate_shapes(n):
    if n == 1:
        return [[[1]]]

    shapes = []
    seen = set()

    def add_shape(shape):
        # Normalize the shape to avoid duplicates
        min_x = min(x for x, y in shape)
        min_y = min(y for x, y in shape)
        normalized = frozenset((x - min_x, y - min_y) for x, y in shape)
        if normalized not in seen:
            seen.add(normalized)
            shapes.append(shape)

    def can_add(shape, new_block):
        return all((x + new_block[0], y + new_block[1]) not in shape for x, y in shape)

    def place_block(shape, new_block):
        return [(x + new_block[0], y + new_block[1]) for x, y in shape]

    def search(shape, remaining):
        if remaining == 0:
            add_shape(shape)
            return

        for dx, dy in [(1, 0), (0, 1), (-1, 0), (0, -1)]:
            new_block = (dx, dy)
            if can_add(shape, new_block):
                new_shape = place_block(shape, new_block)
                search(new_shape, remaining - 1)

    search([(0, 0)], n - 1)
    return shapes

