        return [[[1, 1]]]

    shapes = []

    def add_shape(shape):
        if shape not in shapes:
            shapes.append(shape)

    def rotate(shape):
        return [list(reversed(col)) for col in zip(*shape)]

    def flip(shape):
        return [row[::-1] for row in shape]

    def normalize(shape):
        return sorted(tuple(map(tuple, shape)))

    def generate(n, current_shape):
        if len(current_shape) == n:
            add_shape(normalize(current_shape))
            return

        for i in range(len(current_shape)):
            for j in range(len(current_shape[i])):
                if current_shape[i][j] == 0:
                    continue

                for di, dj in [(0, 1), (1, 0), (0, -1), (-1, 0)]:
                    new_shape = [row[:] for row in current_shape]
                    new_shape[i][j] = 0
                    ni, nj = i + di, j + dj
                    if 0 <= ni < len(new_shape) and 0 <= nj < len(new_shape[0]) and new_shape[ni][nj] == 0:
