    if n < 1:
        return []

    shapes = set()

    def rotate(shape):
        return set((y, -x) for x, y in shape)

    def reflect(shape):
        return set((-x, y) for x, y in shape)

    def add_shape(shape):
        normalized = frozenset(sorted(shape))
        shapes.add(normalized)

    def backtrack(current_shape, remaining):
        if remaining == 0:
            add_shape(current_shape)
            return

        start = current_shape[-1] if current_shape else (0, 0)
        for dx in range(-1, 2):
            for dy in range(-1, 2):
