def generate_shapes(n):
    if n < 1:
        return []

    shapes = set()

    def rotate(shape):
        return set((y, -x) for x, y in shape)

    def reflect(shape):
        return set((-x, y) for x, y in shape)

    def add_shape(shape):
        canonical = frozenset(shape)
        shapes.add(canonical)

    def generate(current_shape, remaining):
        if remaining == 0:
            add_shape(current_shape)
            return

        last_x, last_y = current_shape[-1] if current_shape else (0, 0)
        for dx, dy in [(1, 0), (0, 1), (-1, 0), (0, -1)]:
            new_square = (last_x + dx, last_y + dy)
            if new_square not in current_shape:
                generate(current_shape + [new_square], remaining - 1)

    generate([], n)

    unique_shapes = set()
    for shape in shapes:
        transformed = set()
        current_shape = shape
        for _ in range(4):
            current_shape = rotate(current_shape)
            transformed.add(frozenset(current_shape))
            transformed.add(frozenset(reflect(current_shape)))
